	{ hex: "#AED6F1", name: "Sky" },
	{ hex: "#A9DFBF", name: "Mint" },
	{ hex: "#F9E79F", name: "Cream" },
	{ hex: "#F5CBA7", name: "Peach" },
	{ hex: "#E59866", name: "Bronze" }
];

function hexToRgb(hex) {
	const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
	return result
		? {
				r: parseInt(result[1], 16),
				g: parseInt(result[2], 16),
				b: parseInt(result[3], 16)
		  }
		: null;
}

function getColorName(hex) {
	let minDist = Infinity;
	let closestName = "Custom";
	const rgb1 = hexToRgb(hex);

	if (!rgb1) return "Custom";

	aestheticNames.forEach((c) => {
		const rgb2 = hexToRgb(c.hex);
		const dist = Math.sqrt(
			Math.pow(rgb2.r - rgb1.r, 2) +
				Math.pow(rgb2.g - rgb1.g, 2) +
				Math.pow(rgb2.b - rgb1.b, 2)
		);
		if (dist < minDist) {
			minDist = dist;
			closestName = c.name;
		}
	});
	return closestName;
}

function getLuminance(r, g, b) {
	var a = [r, g, b].map(function (v) {
		v /= 255;
		return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
	});
	return a[0] * 0.2126 + a[1] * 0.7152 + a[2] * 0.0722;
}

function getContrastRatio(hex1, hex2) {
	const rgb1 = hexToRgb(hex1);
	const rgb2 = hexToRgb(hex2);
	if (!rgb1 || !rgb2) return 1;
	const lum1 = getLuminance(rgb1.r, rgb1.g, rgb1.b);
	const lum2 = getLuminance(rgb2.r, rgb2.g, rgb2.b);
	const brightest = Math.max(lum1, lum2);
	const darkest = Math.min(lum1, lum2);
	return (brightest + 0.05) / (darkest + 0.05);
}

const inputs = [
	document.getElementById("input-1"),
	document.getElementById("input-2"),
	document.getElementById("input-3"),
	document.getElementById("input-4"),
	document.getElementById("input-5")
];

function updateUI() {
	let colors = [];
	inputs.forEach((input, index) => {
		const color = input.value;
		colors.push(color);

		document.getElementById(`block-${index + 1}`).style.backgroundColor = color;
		document.getElementById(`hex-${index + 1}`).innerText = color.toUpperCase();

		const currentName = document.getElementById(`name-${index + 1}`).innerText;
		const newName = getColorName(color);
		if (currentName === "Custom" || currentName !== newName) {
			document.getElementById(`name-${index + 1}`).innerText = newName;
		}
	});

	const rgbBase = hexToRgb(colors[0]);
	if (rgbBase) {
		const lum = getLuminance(rgbBase.r, rgbBase.g, rgbBase.b);
		document.getElementById("lum-display").innerText = lum.toFixed(2);
	}

	let maxContrast = 0;
	for (let i = 1; i < colors.length; i++) {
		const currentContrast = getContrastRatio(colors[0], colors[i]);
		if (currentContrast > maxContrast) maxContrast = currentContrast;
	}

	let grade = "Low";
	if (maxContrast > 3) grade = "A";
	if (maxContrast > 4.5) grade = "AA";
	if (maxContrast > 7) grade = "AAA";

	document.getElementById("contrast-display").innerText = grade;
}

inputs.forEach((input) => {
	input.addEventListener("input", updateUI);
});

function hexToHsl(hex) {
	let { r, g, b } = hexToRgb(hex);
	(r /= 255), (g /= 255), (b /= 255);
	let max = Math.max(r, g, b),
		min = Math.min(r, g, b);
	let h,
		s,
		l = (max + min) / 2;
	if (max == min) {
		h = s = 0;
	} else {
		let d = max - min;
		s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
		switch (max) {
			case r:
				h = (g - b) / d + (g < b ? 6 : 0);
				break;
			case g:
				h = (b - r) / d + 2;
				break;
			case b:
				h = (r - g) / d + 4;
				break;
		}
		h /= 6;
	}
	return { h: h * 360, s: s * 100, l: l * 100 };
}

function hslToHex(h, s, l) {
	l /= 100;
	const a = (s * Math.min(l, 1 - l)) / 100;
	const f = (n) => {
		const k = (n + h / 30) % 12;
		const color = l - a * Math.max(Math.min(k - 3, 9 - k, 1), -1);
		return Math.round(255 * color)
			.toString(16)
			.padStart(2, "0");
	};
	return `#${f(0)}${f(8)}${f(4)}`;
}

function generateHarmony() {
	const baseColor = inputs[0].value;
	const hsl = hexToHsl(baseColor);

	const c1 = baseColor;
	const c2 = hslToHex(hsl.h, Math.max(0, hsl.s - 20), Math.max(10, hsl.l - 15));
	const c3 = hslToHex((hsl.h + 180) % 360, hsl.s, hsl.l);
	const c4 = hslToHex(hsl.h, 10, 90);
	const c5 = hslToHex((hsl.h + 30) % 360, Math.max(0, hsl.s - 10), hsl.l);

	inputs[1].value = c2;
	inputs[2].value = c3;
	inputs[3].value = c4;
	inputs[4].value = c5;

	updateUI();
	document.getElementById("rule-display").innerText = "Split-Compl.";
}

function downloadImage() {
	const element = document.getElementById("infographic-container");
	cursorDot.style.display = "none";
	cursorOutline.style.display = "none";
	const originalTransform = tiltCard.style.transform;
	tiltCard.style.transform = "none";

	html2canvas(element, { scale: 2, useCORS: true, backgroundColor: null }).then(
		(canvas) => {
			const link = document.createElement("a");
			link.download = "CalculateQuick-Color-Board.png";
			link.href = canvas.toDataURL("image/png");
			link.click();
			tiltCard.style.transform = originalTransform;
			cursorDot.style.display = "block";
			cursorOutline.style.display = "block";
		}
	);
}

document.querySelectorAll("a, button, input").forEach((el) => {
	el.addEventListener("mouseenter", () => {
		cursorOutline.style.transform = "translate(-50%, -50%) scale(1.5)";
		cursorOutline.style.borderColor = "#C45B3E";
	});
	el.addEventListener("mouseleave", () => {
		cursorOutline.style.transform = "translate(-50%, -50%) scale(1)";
		cursorOutline.style.borderColor = "#1A1A1A";
	});
});

document.querySelectorAll("[contenteditable]").forEach((el) => {
	el.addEventListener("mouseenter", () => {
		cursorOutline.style.borderStyle = "dashed";
	});
	el.addEventListener("mouseleave", () => {
		cursorOutline.style.borderStyle = "solid";
	});
});

updateUI();

style.css:
:root {
	--bg-color: #f0f0eb;
	--text-main: #1a1a1a;
	--text-sub: #555555;
	--accent: #c45b3e;
	--border: rgba(0, 0, 0, 0.1);
}

* {
	box-sizing: border-box;
	margin: 0;
	padding: 0;
	cursor: none;
}

body {
	background-color: #111;
	display: flex;
	flex-direction: column;
	justify-content: center;
	align-items: center;
	min-height: 100vh;
	font-family: "Space Mono", monospace;
	overflow-x: hidden;
}

.cursor-dot,
.cursor-outline {
	position: fixed;
	top: 0;
	left: 0;
	transform: translate(-50%, -50%);
	border-radius: 50%;
	z-index: 9999;
	pointer-events: none;
}

.cursor-dot {
	width: 8px;
	height: 8px;
	background-color: var(--accent);
}

.cursor-outline {
	width: 40px;
	height: 40px;
	border: 1px solid var(--text-main);
	transition: width 0.2s, height 0.2s, background-color 0.2s;
}

.app-container {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 20px;
	padding: 20px;
}

#infographic-container {
	width: 90vw;
	height: 80vh;
	max-width: 1200px;
	max-height: 800px;
	background-color: var(--bg-color);
	position: relative;
	display: grid;
	grid-template-columns: 300px 1fr;
	overflow: hidden;
	box-shadow: 0 20px 50px rgba(0, 0, 0, 0.3);
}

#infographic-container::after {
	content: "";
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.08'/%3E%3C/svg%3E");
	pointer-events: none;
	z-index: 50;
	mix-blend-mode: multiply;
}

.sidebar {
	padding: 60px 40px;
	display: flex;
	flex-direction: column;
	justify-content: space-between;
	border-right: 1px solid var(--border);
	z-index: 2;
}

h1 {
	font-family: "Playfair Display", serif;
	font-size: 42px;
	line-height: 1.1;
	font-weight: 400;
	color: var(--text-main);
	margin-bottom: 20px;
	outline: none;
	border-bottom: 1px solid transparent;
	transition: border-color 0.3s;
}

h1:hover,
.subtitle:hover,
span[contenteditable]:hover {
	background-color: rgba(0, 0, 0, 0.03);
	cursor: text;
}

h1:focus,
.subtitle:focus,
span[contenteditable]:focus {
	border-bottom: 1px solid var(--accent);
	background: rgba(0, 0, 0, 0.02);
}

.subtitle {
	font-size: 11px;
	line-height: 1.6;
	color: var(--text-sub);
	max-width: 200px;
	outline: none;
}

.meta-data {
	margin-top: auto;
}

.meta-row {
	display: flex;
	justify-content: space-between;
	border-top: 1px solid var(--border);
	padding: 15px 0;
	font-size: 10px;
	color: var(--text-sub);
}

.palette-stage {
	position: relative;
	perspective: 1000px;
	display: flex;
	align-items: center;
	justify-content: center;
	z-index: 1;
}

.swatch-container {
	position: relative;
	width: 60%;
	height: 70%;
	transform-style: preserve-3d;
	transition: transform 0.1s ease-out;
	display: flex;
	flex-direction: column;
	gap: 15px;
}

.swatch-row {
	flex: 1;
	display: flex;
	align-items: center;
	background: white;
	box-shadow: 0 10px 30px -10px rgba(0, 0, 0, 0.15);
	transition: transform 0.3s ease;
	position: relative;
}

.swatch-row:hover {
	transform: scale(1.02) translateZ(20px) !important;
	z-index: 10;
}

.color-block {
	width: 150px;
	height: 100%;
	transition: background-color 0.5s cubic-bezier(0.25, 1, 0.5, 1);
}

.swatch-info {
	padding: 0 30px;
	flex: 1;
	display: flex;
	justify-content: space-between;
	align-items: center;
	font-size: 11px;
	color: var(--text-sub);
	border-left: 1px solid var(--border);
}

.hex-code {
	font-weight: 700;
	color: var(--text-main);
	opacity: 0.5;
	transition: opacity 0.3s;
}

.swatch-row:hover .hex-code {
	opacity: 1;
}

.c1 {
	width: 90%;
	margin-left: 5%;
}
.c2 {
	width: 100%;
}
.c3 {
	width: 85%;
	margin-left: 10%;
}
.c4 {
	width: 95%;
	margin-left: 2%;
}
.c5 {
	width: 88%;
	margin-left: 6%;
}

.attribution {
	position: absolute;
	bottom: 40px;
	right: 40px;
	z-index: 60;
	font-family: "Playfair Display", serif;
	font-style: italic;
	font-size: 14px;
}

.attribution a {
	color: var(--text-main);
	text-decoration: none;
	position: relative;
	padding-bottom: 2px;
	cursor: none;
}

.controls-panel {
	background: #1a1a1a;
	padding: 15px 30px;
	border-radius: 8px;
	display: flex;
	align-items: center;
	justify-content: space-between;
	gap: 40px;
	border: 1px solid #333;
	width: 90vw;
	max-width: 1200px;
}

.panel-section {
	display: flex;
	flex-direction: column;
	gap: 8px;
}

.panel-label {
	color: #666;
	font-size: 9px;
	text-transform: uppercase;
	letter-spacing: 1px;
}

.color-pickers {
	display: flex;
	gap: 15px;
}

.picker-wrapper {
	position: relative;
	display: flex;
	align-items: center;
	justify-content: center;
}

input[type="color"] {
	-webkit-appearance: none;
	border: none;
	width: 32px;
	height: 32px;
	border-radius: 50%;
	overflow: hidden;
	cursor: pointer !important;
	background: none;
	transition: transform 0.2s;
}

input[type="color"]:hover {
	transform: scale(1.15);
}

input[type="color"]::-webkit-color-swatch-wrapper {
	padding: 0;
}

input[type="color"]::-webkit-color-swatch {
	border: 2px solid #555;
	border-radius: 50%;
}

.btn {
	border: none;
	padding: 10px 20px;
	font-family: "Space Mono", monospace;
	font-size: 11px;
	text-transform: uppercase;
	letter-spacing: 0.5px;
	cursor: pointer !important;
	transition: transform 0.2s, background 0.2s;
	border-radius: 4px;
	height: 36px;
}

.btn-primary {
	background: #fff;
	color: #000;
}

.btn-primary:hover {
	transform: translateY(-2px);
	background: #e3dcd2;
}

.btn-secondary {
	background: transparent;
	color: #ccc;
	border: 1px solid #444;
}

.btn-secondary:hover {
	background: #333;
	color: #fff;
	border-color: #666;
}

.hint-text {
	color: #666;
	font-size: 11px;
	font-family: "Space Mono", monospace;
}

@media (max-width: 900px) {
	#infographic-container {
		grid-template-columns: 1fr;
		height: auto;
		padding-bottom: 40px;
	}
	.sidebar {
		padding: 30px;
		border-right: none;
		border-bottom: 1px solid rgba(0, 0, 0, 0.05);
	}
	.palette-stage {
		padding: 40px 0;
		min-height: 400px;
	}
	.controls-panel {
		flex-direction: column;
		height: auto;
		align-items: stretch;
		gap: 20px;
		padding: 20px;
	}
	.panel-section {
		align-items: center;
	}
}
